#include <array>
#include <iostream>

void reverseArray(std::array<int, 5>& arr) {
    for (std::size_t i = 0; i < arr.size() / 2; ++i) {
        int tmp = arr[i];
        arr[i] = arr[arr.size() - 1 - i];
        arr[arr.size() - 1 - i] = tmp;
    }
}

int main() {
    std::array<int, 5> nums {};
    for (std::size_t i = 0; i < nums.size(); ++i) {
        std::cin >> nums[i];
    }
    reverseArray(nums);
    for (std::size_t i = 0; i < nums.size(); ++i) {
        if (i > 0) std::cout << ' ';
        std::cout << nums[i];
    }
    std::cout << '\n';
    return 0;
}

